import React, { useState } from "react";
import axios from "axios";

export default function CampaignCard({ type }) {
  const [message, setMessage] = useState("");
  const [recipients, setRecipients] = useState("");
  const [loading, setLoading] = useState(false);

  const sendCampaign = async () => {
    if (!message || !recipients) {
      alert("Please fill in all fields");
      return;
    }

    setLoading(true);
    try {
      const token = localStorage.getItem("token");
      await axios.post(
        "http://localhost:5000/api/campaigns",
        {
          name: `${type} Campaign`,
          type: type.toLowerCase(),
          message,
          recipients: parseInt(recipients)
        },
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );
      alert("Campaign sent successfully!");
      setMessage("");
      setRecipients("");
    } catch (error) {
      console.error("Error sending campaign:", error);
      alert("Failed to send campaign");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded shadow">
      <h2 className="text-lg font-bold mb-4">{type} Campaign</h2>
      
      <div className="mb-3">
        <label className="block text-sm font-medium mb-1">Number of Recipients</label>
        <input
          type="number"
          className="border p-2 w-full"
          placeholder="Enter number of recipients"
          value={recipients}
          onChange={(e) => setRecipients(e.target.value)}
        />
      </div>

      <div className="mb-3">
        <label className="block text-sm font-medium mb-1">Message Template</label>
        <textarea
          className="border p-2 w-full"
          placeholder="Enter your message here..."
          rows={4}
          value={message}
          onChange={(e) => setMessage(e.target.value)}
        />
      </div>

      <button
        className={`w-full py-2 rounded text-white ${
          loading
            ? "bg-gray-400 cursor-not-allowed"
            : "bg-green-500 hover:bg-green-600"
        }`}
        onClick={sendCampaign}
        disabled={loading}
      >
        {loading ? "Sending..." : "Send Campaign"}
      </button>
    </div>
  );
}
